import clsx from 'clsx';

import { CriticalIcon } from '@dynatrace/strato-icons';

import * as styles from './FormFieldMessageItem.sty.js';
import { useBehavioralTrackingProps } from '../../../../core/hooks/useBehavioralTrackingProps.js';
import type { BehaviorTrackingProps } from '../../../../core/types/behavior-tracking-props.js';
import { DataTestId } from '../../../../core/types/data-props.js';
import { DOMProps } from '../../../../core/types/dom.js';
import { StylingProps } from '../../../../core/types/styling-props.js';
import { WithChildren } from '../../../../core/types/with-children.js';
import { Flex } from '../../../../layouts/flex/Flex.js';
import { useFormFieldMessagesContext } from '../../hooks/useFormFieldMessagesContext.js';

/**
 * @public
 */
export interface FormFieldMessageBaseItemProps
  extends WithChildren,
    StylingProps,
    DOMProps,
    DataTestId,
    BehaviorTrackingProps {
  /**
   * Determines the style of the message (text color, icon).
   * Error messages additionally prevent the form component
   * from being submitted in a form.
   */
  variant?: 'error' | 'hint';
  /**
   * Whether the connected input is currently disabled.
   * @defaultValue false
   */
  disabled?: boolean;
}

/**
 * Renders a Form Field Message.
 * @internal
 */
export const InternalBaseItem = (props: FormFieldMessageBaseItemProps) => {
  const {
    children,
    variant = 'hint',
    className: consumerClassName,
    style: consumerStyle,
    disabled: propDisabled = false,
    'data-testid': dataTestId,
    id: propId,
    ...remainingProps
  } = props;

  const [behavioralTrackingProps] = useBehavioralTrackingProps(remainingProps);

  const { disabled: contextDisabled } = useFormFieldMessagesContext();
  const disabled = propDisabled || contextDisabled;

  return (
    <Flex
      className={clsx(
        styles.formFieldMessageItem({ variant, disabled }),
        consumerClassName,
      )}
      style={consumerStyle}
      alignItems="flex-start"
      gap={4}
      data-testid={dataTestId}
      id={propId}
      {...behavioralTrackingProps}
    >
      {variant === 'error' && (
        <Flex>
          <CriticalIcon size="small" />
        </Flex>
      )}
      <div className={styles.formFieldMessageItemText}>{children}</div>
    </Flex>
  );
};

InternalBaseItem.displayName = 'FormFieldMessageItem';
